with gfl_batch as (
  select id as batch_id
  from public.supplier_import_batches
  where supplier = 'Gear For Life'
    and source_file_hash = 'f20ede9ac24d944fcb4c3c646d8ae2cbc41d2c63580200db27f2e86a96bf739c'
  order by created_at desc
  limit 1
)
insert into public.supplier_raw_images (
  batch_id, supplier, supplier_sku, image_url, image_role, colour_key, colour_name, source_image_id, sort_order, raw_json
)
select
  gfl_batch.batch_id,
  v.supplier::text, v.supplier_sku::text, v.image_url::text, v.image_role::text, v.colour_key::text, v.colour_name::text, v.source_image_id::text, v.sort_order::text, v.raw_json::jsonb
from gfl_batch
